        "questions": [
          {
            "type": "mcq",
            "q": "Let $K/\\mathbb{Q}$ be Galois with group $G$, and let $\\mathfrak{P}\\subset\\mathcal{O}_K$ be an unramified prime above a rational prime $p$. The Frobenius element $\\mathrm{Frob}_\\mathfrak{P}\\in G$ is characterised by:",
            "choices": [
              "$\\mathrm{Frob}_\\mathfrak{P}(x)=px$ for all $x\\in\\mathcal{O}_K$",
              "$\\mathrm{Frob}_\\mathfrak{P}(x)\\equiv x^p\\pmod{\\mathfrak{P}}$ for all $x\\in\\mathcal{O}_K$",
              "$\\mathrm{Frob}_\\mathfrak{P}$ is the identity in $G$ for every unramified $\\mathfrak{P}$",
              "$\\mathrm{Frob}_\\mathfrak{P}(x)=x+p$ for all $x\\in\\mathcal{O}_K$"
            ],
            "answer": 1,
            "explain": "The Frobenius is the unique element of the decomposition group whose image in the residue-field Galois group is the $p$-power map $x\\mapsto x^p$; equivalently $\\mathrm{Frob}_\\mathfrak{P}(x)\\equiv x^p\\pmod{\\mathfrak{P}}$."
          },
          {
            "type": "mcq",
            "q": "If $\\mathfrak{P}$ and $\\mathfrak{P}'$ are two unramified primes of $\\mathcal{O}_K$ lying over the same rational prime $p$, the Frobenius elements $\\mathrm{Frob}_\\mathfrak{P}$ and $\\mathrm{Frob}_{\\mathfrak{P}'}$ are:",
            "choices": [
              "equal in $G$",
              "inverses of each other",
              "conjugate in $G$",
              "unrelated in general"
            ],
            "answer": 2,
            "explain": "Any two primes above $p$ are related by an element of $G$ (Galois acts transitively on primes above $p$), and conjugating the prime conjugates the Frobenius. So $\\mathrm{Frob}_p$ is a well-defined conjugacy class in $G$."
          },
          {
            "type": "numeric",
            "q": "For $f(x)=x^3-x-1$ (Galois group $S_3$), a prime $p$ with factorisation $\\bar f(x)\\bmod p=(\\deg 2)\\cdot(\\deg 1)$ has Frobenius of cycle shape a single transposition. What is the order of $\\mathrm{Frob}_p$ in $S_3$?",
            "answer": 2,
            "tol": 0.000001,
            "explain": "A transposition in $S_3$ has order $2$: applying it twice returns the identity."
          }
        ]
